import itertools, math, collections, functools, statistics
def min_twice(vals):
    m=min(vals)
    return vals.count(m)>=2
def check_rank2_val(p,n):
    # p dict pair sorted -> val
    for Q in itertools.combinations(range(n),4):
        i,j,k,l=Q
        vals=[p[tuple(sorted((i,j)))]+p[tuple(sorted((k,l)))],
              p[tuple(sorted((i,k)))]+p[tuple(sorted((j,l)))],
              p[tuple(sorted((i,l)))]+p[tuple(sorted((j,k)))]]
        if not min_twice(vals):
            return False, ("pl",Q,vals)
    return True,None
def check_quot_U3(p,n):
    # p rank2 quotient to U3n
    for T in itertools.combinations(range(n),4):
        for s in T:
            vals=[p[tuple(sorted((s,i)))] for i in T if i!=s]
            if not min_twice(vals):
                return False, ("inc",T,s,vals)
    return True,None
n=5
pairs=list(itertools.combinations(range(n),2))
solutions=[]
for vals in itertools.product(range(3), repeat=len(pairs)):
    if min(vals)!=0: continue
    p=dict(zip(pairs,vals))
    ok,_=check_rank2_val(p,n)
    if not ok: continue
    ok2,_=check_quot_U3(p,n)
    if not ok2: continue
    hs={B:min(p[tuple(sorted(e))] for e in itertools.combinations(B,2)) for B in itertools.combinations(range(n),3)}
    if len(set(hs.values()))>1:
